class Solution:
    def countQuadruplets(self, nums):
        n = len(nums)
        total = 0
        present = [False] * (n + 1)
        for j in range(n):
            t = nums[j]
            cum = [0] * (n + 1)
            for v in range(1, n + 1):
                cum[v] = cum[v - 1] + (1 if present[v] else 0)
            g = [0] * n
            for k in range(n - 2, j - 1, -1):
                g[k] = g[k + 1] + (1 if nums[k + 1] > t else 0)
            row_total = 0
            for k in range(j + 1, n):
                if t > nums[k]:
                    row_total += cum[nums[k] - 1] * g[k]
            total += row_total
            present[t] = True
        return total

