var countQuadruplets = function(nums) {
    const n = nums.length;
    let total = 0;
    const present = new Array(n + 1).fill(false);
    for (let j = 0; j < n; j++) {
        const t = nums[j];
        const cum = new Array(n + 1).fill(0);
        for (let v = 1; v <= n; v++) {
            cum[v] = cum[v - 1] + (present[v] ? 1 : 0);
        }
        const g = new Array(n).fill(0);
        for (let k = n - 2; k >= j; k--) {
            g[k] = g[k + 1] + (nums[k + 1] > t ? 1 : 0);
        }
        for (let k = j + 1; k < n; k++) {
            if (t > nums[k]) {
                total += cum[nums[k] - 1] * g[k];
            }
        }
        present[t] = true;
    }
    return total;
};
